previewCss:
.darma-loader-darma-custom-116 {
  width: 50px;
  aspect-ratio: 1;
  display: grid;
}
.darma-loader-darma-custom-116:before,
.darma-loader-darma-custom-116:after {
  content: "";
  grid-area: 1/1;
  border-radius: 50%;
  background: #f03355;
  -webkit-mask:repeating-linear-gradient(#000 0 10px,#0000 0 20px);
}
.darma-loader-darma-custom-116:after {
  -webkit-mask:repeating-linear-gradient(#0000 0 10px,#000 0 20px);
  animation: darma-loader-darma-custom-116-l36 1.5s infinite;
}
@keyframes darma-loader-darma-custom-116-l36 {
  0%,
  10%  {transform: rotate(0)      translate(0)}
  35%  {transform: rotate(0)      translate(100%)}
  66%  {transform: rotate(180deg) translate(100%)}
  90%,
  100% {transform: rotate(180deg) translate(0) }
}

